mapper.select:
SELECT DATE_FORMAT(reserved_at, '%H:%i') as time
FROM reservation
WHERE DATE(reserved_at) = #{date}
  AND status = 'RESERVED'

  AND menu_id = #{menuId}

ORDER BY reserved_at

SELECT COUNT(*) > 0
FROM reservation
WHERE reserved_at = #{reservedAt}
  AND menu_id = #{menuId}
  AND status = 'RESERVED'

SELECT COUNT(*) > 0
FROM users
WHERE user_id = #{userId}

SELECT * FROM reservation 
WHERE user_id = #{userId}
ORDER BY reserved_at DESC
